execute:
// **********************************************************
    // @description Enrich Response with UI Metadata from Cache
    //
    // @param   {object} data - computed result or input payload
    // @param   {object} $    - {tenant, paramsId, params, payload, endpointConfig}
    // @param   {object} ctx  - opentracing context
    // @param   {object} this - ARES
    //
    // @return  {object} data - data object enriched
    // **********************************************************
    const { tenant, params, payload, endpointConfig } = $;
    const keys = [];
    const ids = [];
    const skipContentTypes = ["link"];
    const idTypeMap = new Map();
    const missingMap = new Map();
    const typeCache = new Map();
    const labelCache = new Map();
    const contentIdFieldMap = new Map();

    const skipThis = this.get(payload, "query.skipMPXDecorator") || false;
    const typeField = this.get(payload, "query.decoratorTypeField") || "programtype";
    const includeMPXAdvancedStats = this.get(payload, "query.includeMPXAdvancedStats") || false;
    const environment = this.get(payload, "query.decoratorOutputEnvironment") || "production";
    const version =  this.get(payload, "query.decoratorOutputVersion") || "v2";
    const application = this.get(payload, "query.decoratorOutputApplication") || "default";
    const rootUrlSuffix = { commerce: "f4lFhC", production: "PR1GhC" };
    const rootUrl = `https://feed.entertainment.tv.theplatform.eu/f/${rootUrlSuffix[environment]}/`;
    const cacheTTL = this.get(endpointConfig,"params.cacheConfig.cacheTTL") || 86400;

    if(skipThis) return data;

    // **************************************
    // Table for all editorialType
    // divided by version v1 or v2
    // **************************************
    const endpointTable = [
      {
        label: "all-programs",
        v1: {
          environments: {
            commerce: "mst-dev-playg-all-programs",
            production: "mediaset-prod-all-programs",
          },
          types: new Set(["Episode", "Movie", "Clip", "DigitalFirst"]),
          fields: {
            default:
              "guid,title,description,programType,thumbnails,media.expirationDate,media.availableDate,media.publicUrl,longDescription,year,seriesId,tvSeasonEpisodeNumber,tvSeasonNumber,mediasetprogram$videoPageUrl,mediasetprogram$numberOfViews,mediasetprogram$genres,ratings,tags,mediasetprogram$duration,mediasetprogram$pageUrl,mediasetprogram$publishInfo,mediasetprogram$publishInfo_lastPublished,mediasetprogram$brandDescription,mediasetprogram$brandId,mediasetprogram$brandTitle,mediasetprogram$subBrandId,mediasetprogram$subBrandTitle,mediasetprogram$episodeId,seriesId,mediasetprogram$sourceAspectRatio,mediasetprogram$subBrandDescription",
          },
        },
        v2: {
          environments: {
            commerce: "mediaset-comm-all-programs-v2",
            production: "mediaset-prod-all-programs-v2"
          },
          types: new Set(["extra","Episode", "episode","Movie","movie","Clip","clip","DigitalFirst","digitalfirst"]),
          fields: {
            default:
              "id,guid,updated,title,description,programType,thumbnails,longDescription,year,seriesId,tvSeasonId,tvSeasonEpisodeNumber,tvSeasonNumber,mediasetprogram$videoPageUrl,mediasetprogram$genres,ratings,tags,mediasetprogram$duration,mediasetprogram$pageUrl,mediasetprogram$publishInfo,mediasetprogram$publishInfo_lastPublished,mediasetprogram$brandTitle,mediasetprogram$episodeId,mediasetprogram$channelsRights,mediasetprogram$countryProduction,mediasetprogram$editorialType,mediasetprogram$expirationDatePerChannelRight",
          },
        },
      },
      {
        label: "all-series",
        v1: {
          environments: {
            commerce: "mst-dev-playg-all-series",
            production: "mediaset-prod-all-series",
          },
          types: new Set(["Serie"]),
          fields: {
            default:
              "guid,title,description,programType,thumbnails,longDescription,year,tvSeasonEpisodeNumber,tvSeasonNumber,mediasetprogram$videoPageUrl,mediasetprogram$numberOfViews,mediasetprogram$genres,ratings,tags,mediasetprogram$duration,mediasetprogram$pageUrl,mediasetprogram$publishInfo,mediasetprogram$publishInfo_lastPublished,mediasetprogram$brandDescription,mediasetprogram$brandId,mediasetprogram$brandTitle,mediasetprogram$subBrandId,mediasetprogram$subBrandTitle,mediasetprogram$episodeId,seriesId,mediasetprogram$sourceAspectRatio,mediasetprogram$subBrandDescription",
          },
        },
        v2: {
          environments: {
            commerce: "mediaset-comm-all-series-v2",
            production: "mediaset-prod-all-series-v2"
          },
          types: new Set(["Serie","series"]),
          fields: {
            default:
              "id,guid,updated,title,description,programType,thumbnails,longDescription,ratings,tags,year,mediasetprogram$channelsRights,mediasetprogram$countryProduction,mediasetprogram$currentSeason,mediasetprogram$genres,mediasetprogram$pageUrl,seriesTvSeasons,availableTvSeasonIds",
          },
        },
      },
      {
        label: "tv-seasons",
        v1: {
          environments: {
            commerce: "mst-dev-playg-all-brands",
            production: "mediaset-prod-all-brands",
          },
          endpointSuffix: "&byTags=contentgroup:Brand&byCustomValue=",
          contentIdField: "id_brand",
          idsDecorator: (ids) => `{brandId}{${ids.join("|")}}`,
          types: new Set(["TVSeason"]),
          fields: {
            default:""
          },
        },
        v2: {
          environments: {
            commerce: "mediaset-comm-tv-seasons-v2",
            production: "mediaset-prod-tv-seasons-v2"
          },
          types: new Set(["TVSeason","season"]),
          fields: {
            default:""
          },
        },
      },
    ];

function getEndpoint(type, label) {
      if (type && typeCache.has(type)) return typeCache.get(type);
      if (label && labelCache.has(label)) return labelCache.get(label);

      for (const entry of endpointTable) {
        const vEntry = entry[version];
        const fields = vEntry.fields[application];

        if (vEntry.types.has(type)) {
          const suffix = vEntry.endpointSuffix || "&byGuid=";
          const endpoint = `${rootUrl}${vEntry.environments[environment]}?range=1-300&fields=${fields}${suffix}`;
          const idsDecorator = vEntry.idsDecorator || ((ids) => ids.join("|"));

          const ret = {
            endpoint,
            label: entry.label,
            fields,
            idsDecorator,
          };

          typeCache.set(type, ret);
          labelCache.set(entry.label, ret);

          return ret;
        }
      }

      return {};
    }

    function getCacheKey(tenant, type, id) {
      return `{${tenant}:${type}:ux}:${id}`;
    }

    function getContentIdField(contentType, type) {
      const key = `${contentType}-${type}`;

      if (contentIdFieldMap.has(key)) return contentIdFieldMap.get(key);

      const contentIdField = params.content.types[contentType].contentIdField;
      const customContentIdField = endpointTable.find((entry) => entry[version].types.has(type))[
        version
      ].contentIdField;

      contentIdFieldMap.set(key, customContentIdField || contentIdField);

      return contentIdFieldMap.get(key);
    }

    if (includeMPXAdvancedStats) data.metadata.MPXUniversalDecorator = {typeField};

    // **************************************
    // Get ids, contentType for every element
    // to process and generate Cache Key
    // **************************************
    for (let k = 0, length = data.blocks.length; k < length; k++) {
      const block = data.blocks[k];
      const contentType = block._contentType;

      for (let i = 0, length = block.items.length; i < length; i++) {
        const item = block.items[i];

        // Check Skipped Content Types
         if(skipContentTypes.includes(item._contentType)) continue;

        const type = item[typeField];
        const id = item[getContentIdField(item._contentType ?? contentType, type)];
        const { label,idsDecorator } = getEndpoint(type);

        keys.push(getCacheKey(tenant, type, id));
        ids.push(id);
        idTypeMap.set(id, type);
        if (!missingMap.has(label)) missingMap.set(label, { ids: [], idsDecorator });
      }
    }

    if (includeMPXAdvancedStats) {
       data.metadata.MPXUniversalDecorator.cacheKeysChecked = keys;
    }

    if (!keys.length) return data;



    // **************************************
    // Get UIItems from Cache and check for
    // missing items
    // **************************************
    const values = await this.cache.getKeys(keys);
    const UIMap = new Map();

    for (let i = 0, length = values.length; i < length; i++) {
      const id = ids[i];
      const value = values[i];

      if (!value) {
        const type = idTypeMap.get(id);
        const { label } = getEndpoint(type);

        missingMap.get(label).ids.push(id);
      } else UIMap.set(id, value);
    }

    // **************************************
    // If some UI Enrichment is missing then
    // grab it from MPX and put it in cache
    // **************************************
    if (missingMap.size > 0) {
      const mpxBatch = [];
      const pipeline = this.cache.getPipeline();

      for (const [label, { ids, idsDecorator }] of missingMap.entries()) {
        if (ids.length === 0) continue;

        const { endpoint, fields } = getEndpoint(null, label);
        const url = endpoint + idsDecorator(ids);

        if (includeMPXAdvancedStats) {
          if (!data.metadata.MPXUniversalDecorator.enpointsCalls)
            data.metadata.MPXUniversalDecorator.enpointsCalls = [];
          data.metadata.MPXUniversalDecorator.enpointsCalls.push({
            version,
            environment,
            application,
            MPXType: `${label}`,
            itemsRequested: ids.length,
            fieldsRequested: fields,
            idsRequested: ids,
            url,
          });

          data.metadata.MPXUniversalDecorator.itemsInCache =
            data.pagination.totalHits - ids.length;
        }

         if (endpoint)
          mpxBatch.push(
            this.axios(url).catch((error) => {
              this.logger.error({
                function: "axiosGetMPX",
                errorMessage: error.message,
                error: `GET ${url}`,
              });

              if (includeMPXAdvancedStats) {
                if (!data.metadata.MPXUniversalDecorator.enpointsCallsErrors){
                  data.metadata.MPXUniversalDecorator.enpointsCallsErrors = [];
                }
                data.metadata.MPXUniversalDecorator.enpointsCallsErrors.push(error.message)
              }

              return { data: { entries: [] } };
            })
          );
      }

      const mpxMetadata = await Promise.all(mpxBatch);

      for (const metadataMPX of mpxMetadata) {
        if(!metadataMPX.data) continue;

        for (const uxItem of metadataMPX.data.entries) {
          const id = uxItem.guid || uxItem.mediasetprogram$brandId;
          const type = idTypeMap.get(id);
          const cacheKey = getCacheKey(tenant, type, id);

          UIMap.set(id, uxItem);
          pipeline.set(cacheKey, JSON.stringify(uxItem), "EX", cacheTTL);
        }
      }

      pipeline.exec();
    }

    // **************************************
    // Enrich Blocks with UIItems
    // **************************************
    let totalEnriched = 0;
    for (let blockIndex = 0, length = data.blocks.length; blockIndex < length; blockIndex++) {
      const block = data.blocks[blockIndex];
      const contentType = block._contentType;

      for (let itemIndex = 0, length = block.items.length; itemIndex < length; itemIndex++) {
        const item = block.items[itemIndex];

        // Check Skipped Content Types
         if(skipContentTypes.includes(item._contentType)){
           totalEnriched += 1;
           continue;
         } 

        const type = item[typeField];
        const id = item[getContentIdField(item._contentType ?? contentType, type)];
        const uiEnrich = UIMap.get(id);

        if (!uiEnrich) {
          delete data.blocks[blockIndex].items[itemIndex];
          continue;
        }

        totalEnriched += 1;
        const enriched = typeof uiEnrich === "object" ? uiEnrich : JSON.parse(uiEnrich);

        data.blocks[blockIndex].items[itemIndex] = { ...item, ...enriched };
      }

      data.blocks[blockIndex].items = data.blocks[blockIndex].items.filter((item) => item !== null);
    }

    if (includeMPXAdvancedStats) {
      data.metadata.MPXUniversalDecorator.itemsInChache = values.filter(k => k).length;
      data.metadata.MPXUniversalDecorator.itemsBeforeMPXEnrichment = data.pagination.totalHits;
      data.metadata.MPXUniversalDecorator.itemsRequestedToMPX = data.pagination.totalHits - data.metadata.MPXUniversalDecorator.itemsInChache;
      data.metadata.MPXUniversalDecorator.itemsNotInMPX = data.pagination.totalHits - totalEnriched;
      data.metadata.MPXUniversalDecorator.itemsReturned = totalEnriched;
    }

    data.pagination.totalHits = totalEnriched;

    return data;
